import React, { useState, useEffect } from 'react'
import { API_PERSON, API_KEY, POSTER_PATH, WIDTH_300 } from '../constant';
import { LazyLoadImage } from 'react-lazy-load-image-component';
import axios from 'axios';

const Images = (props) => {

  const { id } = props;
  const [data, setData] = useState([]);

  useEffect(() => {
    const getData = async () => {
      axios.get(API_PERSON + id + '/images?api_key=' + API_KEY)
        .then((data) => {
          setData(data.data.profiles)
        })
        .catch((error) => {
          console.error(error);
        })
    }

    getData();
  }, [id]);

  return (
    <>
      {data.length > 0 ?
        <div>
          <h1 className="mt-5">Gallery</h1>
          <div className="row">
            {data.map((dataRow, index) => (
              <div key={index} className="mb-4 col-6 col-sm-4 col-md-3">
                <LazyLoadImage key={index} className="img-fluid" src={POSTER_PATH + WIDTH_300 + dataRow.file_path} effect="opacity" alt={dataRow.file_path} onError={(e)=>{e.target.onerror = null; e.target.src="https://fakeimg.pl/200x300?text=MoviesHub&font=bebas&font_size=30"}} />
              </div>
            ))}
          </div>
        </div> : ''}
    </>
  )
}

export default Images